import React from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Container,
} from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

// Weather condition emoji mapping
const getWeatherEmoji = (condition: string): string => {
  const lowerCondition = condition.toLowerCase();
  const emojiMap: Record<string, string> = {
    sunny: '☀️',
    'clear': '☀️',
    'mostly clear': '🌤️',
    'partly cloudy': '⛅',
    cloudy: '☁️',
    'mostly cloudy': '☁️',
    overcast: '☁️',
    rainy: '🌧️',
    'light rain': '🌦️',
    'heavy rain': '⛈️',
    thunderstorm: '⛈️',
    snowy: '❄️',
    snow: '❄️',
    windy: '💨',
    foggy: '🌫️',
    hazy: '🌫️',
  };

  for (const [key, emoji] of Object.entries(emojiMap)) {
    if (lowerCondition.includes(key)) {
      return emoji;
    }
  }
  return '🌡️';
};

export default function GeneratedComponent(props: Props): React.ReactElement {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit,
    forecast,
  } = props;

  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Container maxWidth="md" padding={16}>
      <Card shadow="md" padding={24}>
        <Stack direction="vertical" gap={24}>
          {/* Header with City Name */}
          <Text variant="h2" align="center" color="var(--ggui-color-neutral-900, #111827)">
            {city}
          </Text>

          {/* Main Temperature and Condition */}
          <Stack direction="vertical" gap={16} align="center">
            {/* Weather Emoji */}
            <div style={{
              fontSize: '64px',
              lineHeight: 1,
            }}>
              {weatherEmoji}
            </div>

            {/* Temperature Display */}
            <Text
              variant="h1"
              align="center"
              color="var(--ggui-color-primary-600, #0284c7)"
              weight="bold"
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                letterSpacing: '-0.025em',
              }}
            >
              {temperature}°{unit}
            </Text>

            {/* Condition Description */}
            <Text
              variant="body"
              align="center"
              color="var(--ggui-color-neutral-700, #374151)"
              style={{
                fontSize: 'var(--ggui-font-size-lg, 18px)',
              }}
            >
              {condition}
            </Text>
          </Stack>

          {/* Current Weather Details */}
          <Row gap={16} justify="center" align="stretch" wrap={true}>
            {/* Humidity Card */}
            <div
              style={{
                flex: '1 1 calc(50% - 8px)',
                minWidth: '140px',
                padding: 'var(--ggui-spacing-4, 16px)',
                backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                textAlign: 'center',
              }}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-primary-700, #0369a1)"
                style={{
                  fontSize: 'var(--ggui-font-size-sm, 14px)',
                  display: 'block',
                  marginBottom: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                Humidity
              </Text>
              <Text
                variant="body"
                weight="bold"
                color="var(--ggui-color-primary-600, #0284c7)"
                style={{
                  fontSize: 'var(--ggui-font-size-xl, 20px)',
                }}
              >
                {humidity}%
              </Text>
            </div>

            {/* Wind Speed Card */}
            <div
              style={{
                flex: '1 1 calc(50% - 8px)',
                minWidth: '140px',
                padding: 'var(--ggui-spacing-4, 16px)',
                backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                textAlign: 'center',
              }}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-primary-700, #0369a1)"
                style={{
                  fontSize: 'var(--ggui-font-size-sm, 14px)',
                  display: 'block',
                  marginBottom: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                Wind Speed
              </Text>
              <Text
                variant="body"
                weight="bold"
                color="var(--ggui-color-primary-600, #0284c7)"
                style={{
                  fontSize: 'var(--ggui-font-size-xl, 20px)',
                }}
              >
                {windSpeed} {unit === 'F' ? 'mph' : 'km/h'}
              </Text>
            </div>
          </Row>

          {/* Divider */}
          <div
            style={{
              height: '1px',
              backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
            }}
          />

          {/* 5-Day Forecast */}
          <Stack direction="vertical" gap={12}>
            <Text
              variant="h3"
              color="var(--ggui-color-neutral-900, #111827)"
              style={{
                fontSize: 'var(--ggui-font-size-lg, 18px)',
                fontWeight: 'var(--ggui-font-weight-semibold, 600)',
              }}
            >
              5-Day Forecast
            </Text>

            {/* Forecast Strip */}
            <Row gap={8} justify="between" align="start" wrap={true}>
              {forecast.map((day, index) => (
                <div
                  key={index}
                  style={{
                    flex: '1 1 calc(20% - 6.4px)',
                    minWidth: '80px',
                    padding: 'var(--ggui-spacing-3, 12px)',
                    backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                    textAlign: 'center',
                  }}
                >
                  {/* Day Name */}
                  <Text
                    variant="label"
                    color="var(--ggui-color-neutral-700, #374151)"
                    weight="semibold"
                    style={{
                      fontSize: 'var(--ggui-font-size-sm, 14px)',
                      display: 'block',
                      marginBottom: 'var(--ggui-spacing-2, 8px)',
                    }}
                  >
                    {day.day}
                  </Text>

                  {/* Weather Icon/Emoji */}
                  <div
                    style={{
                      fontSize: '28px',
                      lineHeight: 1,
                      marginBottom: 'var(--ggui-spacing-2, 8px)',
                    }}
                  >
                    {day.icon}
                  </div>

                  {/* Temperature Range */}
                  <Stack direction="vertical" gap={2} align="center">
                    <Text
                      variant="caption"
                      weight="bold"
                      color="var(--ggui-color-primary-600, #0284c7)"
                      style={{
                        fontSize: 'var(--ggui-font-size-sm, 14px)',
                      }}
                    >
                      {day.high}°
                    </Text>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-neutral-500, #6b7280)"
                      style={{
                        fontSize: 'var(--ggui-font-size-xs, 12px)',
                      }}
                    >
                      {day.low}°
                    </Text>
                  </Stack>
                </div>
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
